def tail_prob(weights,p):
    m=len(weights)
    prob=0.0
    for mask in range(1<<m):
        s=0; k=0
        for i,w in enumerate(weights):
            if mask>>i &1:
                s+=w; k+=1
        if s+1e-12 >= p:
            prob += (p**k)*((1-p)**(m-k))
    return prob
