import numpy as np, math
def chern_m1(p):
    vals=[]
    for lam in np.linspace(0,20,10001):
        vals.append(math.exp(lam*p)*(1-p+p*math.exp(-lam)))
    return min(vals), np.linspace(0,20,10001)[int(np.argmin(vals))]
