def chern_upper_m1(q):
    vals=[]
    for lam in np.linspace(0,20,10001):
        vals.append(math.exp(-lam*q)*((1-q)+q*math.exp(lam)))
    mi=min(vals); la=np.linspace(0,20,10001)[int(np.argmin(vals))]
